import{_ as t,o as n,c as r,ai as s}from"./chunks/framework.Bke2s2V8.js";const v=JSON.parse('{"title":"Le Konjunktiv II","description":"","frontmatter":{},"headers":[],"relativePath":"module-5-aller-plus-loin/konjunktiv-2.md","filePath":"module-5-aller-plus-loin/konjunktiv-2.md","lastUpdated":1773298982000}'),i={name:"module-5-aller-plus-loin/konjunktiv-2.md"};function o(d,e,a,l,u,m){return n(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="le-konjunktiv-ii" tabindex="-1">Le Konjunktiv II <a class="header-anchor" href="#le-konjunktiv-ii" aria-label="Permalink to “Le Konjunktiv II”">​</a></h1><p><strong>Prérequis :</strong> <a href="./subordonnees.html">Les subordonnées</a></p><p><strong>Objectif :</strong> utiliser le Konjunktiv II pour exprimer l&#39;hypothese, la politesse et le souhait irréel.</p><p>Le Konjunktiv II est le mode du conditionnel en allemand. Il s&#39;utilisé pour parler de situations hypothétiques ou irréelles, et pour formuler des demandes polies.</p><h2 id="les-formes-essentielles-waren-hatten-wurden" tabindex="-1">Les formes essentielles : wären, hätten, würden <a class="header-anchor" href="#les-formes-essentielles-waren-hatten-wurden" aria-label="Permalink to “Les formes essentielles : wären, hätten, würden”">​</a></h2><p>En pratique courante, trois formes couvrent la majorité des situations.</p><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-green-200 bg-green-50"><div class="font-bold text-green-800 text-lg">wären</div><div class="text-sm text-green-700 mt-1">Konjunktiv II de <em>sein</em></div><div class="mt-2 text-sm"><div><em>Wenn ich reich <strong>wäre</strong>...</em> - Si j&#39;étais riche...</div><div><em>Das <strong>wäre</strong> toll.</em> - Ce serait super.</div></div></div><div class="p-4 rounded-xl border border-blue-200 bg-blue-50"><div class="font-bold text-blue-800 text-lg">hätten</div><div class="text-sm text-blue-700 mt-1">Konjunktiv II de <em>haben</em></div><div class="mt-2 text-sm"><div><em>Wenn ich mehr Zeit <strong>hätte</strong>...</em> - Si j&#39;avais plus de temps...</div><div><em>Ich <strong>hätte</strong> gern einen Kaffee.</em> - Je voudrais volontiers un café.</div></div></div><div class="p-4 rounded-xl border border-orange-200 bg-orange-50"><div class="font-bold text-orange-800 text-lg">würden + infinitif</div><div class="text-sm text-orange-700 mt-1">Konjunktiv II de tous les autres verbes (périphrase)</div><div class="mt-2 text-sm"><div><em>Ich <strong>würde</strong> gern reisen.</em> - J&#39;aimerais voyager.</div><div><em>Was <strong>würden</strong> Sie empfehlen ?</em> - Que recommanderiez-vous ?</div></div></div></div><h2 id="conjugaison-de-wurden" tabindex="-1">Conjugaison de würden <a class="header-anchor" href="#conjugaison-de-wurden" aria-label="Permalink to “Conjugaison de würden”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>würden</th></tr></thead><tbody><tr><td>ich</td><td><strong>würde</strong></td></tr><tr><td>du</td><td><strong>würdest</strong></td></tr><tr><td>er/sie/es</td><td><strong>würde</strong></td></tr><tr><td>wir</td><td><strong>würden</strong></td></tr><tr><td>ihr</td><td><strong>würdet</strong></td></tr><tr><td>sie/Sie</td><td><strong>würden</strong></td></tr></tbody></table><h2 id="les-modaux-au-konjunktiv-ii" tabindex="-1">Les modaux au Konjunktiv II <a class="header-anchor" href="#les-modaux-au-konjunktiv-ii" aria-label="Permalink to “Les modaux au Konjunktiv II”">​</a></h2><p>Les modaux ont des formes Konjunktiv II très utilisées, notamment pour la politesse :</p><table tabindex="0"><thead><tr><th>Infinitif</th><th>Konjunktiv II</th><th>Usage</th></tr></thead><tbody><tr><td>können</td><td><strong>könnte</strong></td><td>pourrait / pourriez-vous...</td></tr><tr><td>müssen</td><td><strong>müsste</strong></td><td>devrait</td></tr><tr><td>wollen</td><td><strong>wollte</strong></td><td>voudrait</td></tr><tr><td>dürfen</td><td><strong>dürfte</strong></td><td>pourrait (permission)</td></tr><tr><td>sollen</td><td><strong>sollte</strong></td><td>devrait (conseil)</td></tr></tbody></table><ul><li><em>Konnte ich bitte die Rechnung haben ?</em> - Pourrais-je avoir l&#39;addition ?</li><li><em>Du solltest mehr schlafen.</em> - Tu devrais dormir plus.</li><li><em>Er könnte fruher kommen.</em> - Il pourrait venir plus tot.</li></ul><div class="tip custom-block"><p class="custom-block-title">sollte - le conditionnel du conseil</p><p><em>Du solltest...</em> est la tournure la plus naturelle pour donner un conseil en allemand. Equivalent de &quot;tu devrais...&quot; sans être aussi direct que <em>du musst</em> (tu dois).</p></div><h2 id="les-structures-conditionnelles-avec-wenn" tabindex="-1">Les structures conditionnelles avec wenn <a class="header-anchor" href="#les-structures-conditionnelles-avec-wenn" aria-label="Permalink to “Les structures conditionnelles avec wenn”">​</a></h2><p>La structure complète : <em>Wenn + Konjunktiv II..., ... Konjunktiv II</em>.</p><ul><li><em>Wenn ich Zeit <strong>hätte</strong>, <strong>würde</strong> ich reisen.</em> - Si j&#39;avais le temps, je voyagerais.</li><li><em>Wenn es nicht regnete, <strong>könnten</strong> wir spazieren gehen.</em> - S&#39;il ne pleuvait pas, on pourrait se promener.</li><li><em>Wenn ich du <strong>wäre</strong>, <strong>würde</strong> ich das nicht machen.</em> - A ta place, je ne ferais pas ca.</li></ul><div class="info custom-block"><p class="custom-block-title">Konjunktiv II vs conditionnel français</p><p>La correspondance est directe : <em>wäre</em> = serais/serait, <em>hätte</em> = aurais/aurait, <em>würde + infinitif</em> = ferais/ferait. Les structures conditionnelles fonctionnent de la même façon qu&#39;en français - la syntaxe allemande (verbe en fin dans la subordonnée) s&#39;applique comme d&#39;habitude.</p></div>',18)])])}const h=t(i,[["render",o]]);export{v as __pageData,h as default};
